from pathlib import Path
import base64
import gzip
import subprocess

PATCH_B64 = """[... ELLIPSIZATION ...]"""

patch = gzip.decompress(base64.b64decode(PATCH_B64))
subprocess.run(["git", "apply", "--whitespace=error-all", "-"], input=patch, check=True)

platform_test = Path("tests/platforms.test.js")
source = platform_test.read_text(encoding="utf-8")
old = '''test("submission observation requires a cleared composer or active generation", () => {
  const view = { getComputedStyle: () => ({ visibility: "visible", display: "block", opacity: "1" }) };
  const rect = { left: 0, top: 0, right: 100, bottom: 30, width: 100, height: 30 };
  const composer = {
    nodeType: 1,
    tagName: "TEXTAREA",
    value: "still present",
    disabled: false,
    ownerDocument: { defaultView: view },
    getBoundingClientRect: () => rect,
    getAttribute: () => null
  };
  const stop = {
    nodeType: 1,
    disabled: false,
    ownerDocument: { defaultView: view },
    getBoundingClientRect: () => rect,
    getAttribute: () => null
  };
  const adapter = { composerSelectors: ["composer"], generationSelectors: ["stop"] };
  const documentLike = {
    querySelectorAll(selector) {
      if (selector === "composer") return [composer];
      if (selector === "stop") return [];
      if (selector === "button") return [];
      return [];
    }
  };

  assert.equal(Platforms.submissionObserved(adapter, documentLike), false);
  composer.value = "";
  assert.equal(Platforms.submissionObserved(adapter, documentLike), true);
  composer.value = "still present";
  documentLike.querySelectorAll = (selector) => selector === "composer" ? [composer] : selector === "stop" ? [stop] : [];
  assert.equal(Platforms.submissionObserved(adapter, documentLike), true);
});

test("a missing composer is not treated as delivery confirmation", () => {
  const adapter = { composerSelectors: ["composer"], generationSelectors: ["stop"] };
  const documentLike = { querySelectorAll() { return []; } };
  assert.equal(Platforms.submissionObserved(adapter, documentLike), false);
});'''
new = '''test("submission observation requires a new matching user message", () => {
  const messages = [{ textContent: "same prompt" }];
  const adapter = { userSelectors: ["user"] };
  const documentLike = { querySelectorAll(selector) { return selector === "user" ? messages : []; } };
  const previousSnapshot = Platforms.userMessageSnapshot(adapter, documentLike);

  assert.equal(Platforms.submissionObserved(adapter, { expectedText: "same prompt", previousSnapshot }, documentLike), false);
  messages.push({ textContent: "same prompt" });
  assert.equal(Platforms.submissionObserved(adapter, { expectedText: "same prompt", previousSnapshot }, documentLike), true);
  messages.push({ textContent: "different prompt" });
  assert.equal(Platforms.submissionObserved(adapter, { expectedText: "same prompt", previousSnapshot }, documentLike), false);
});

test("composer clearing or generation alone is not a delivery receipt", () => {
  const adapter = { userSelectors: ["user"] };
  const documentLike = { querySelectorAll() { return []; } };
  assert.equal(Platforms.submissionObserved(adapter, { expectedText: "queued prompt", previousSnapshot: { count: 0, latestText: "" } }, documentLike), false);
});'''
if source.count(old) != 1:
    raise RuntimeError("Expected one legacy submission-observation test block")
platform_test.write_text(source.replace(old, new), encoding="utf-8")
